}

type ProtocolType string

const (
	ProtocolHTTP  ProtocolType = "HTTP"
	ProtocolHTTPS ProtocolType = "HTTPS"
)

type CreateSandboxRequest struct {
	Kind      string `json:"kind"`
	Name      string `json:"name"`
	Namespace string `json:"namespace"`
}

func (r *CreateSandboxRequest) Validate() error {
	if r.Kind == "" {
		return ErrInvalidKind
	}
	if r.Name == "" {
		return ErrInvalidName
	}
	if r.Namespace == "" {
		return ErrInvalidNamespace
	}
	return nil
}

type CreateSandboxResponse struct {
	SessionID   string              `json:"sessionId"`
	SandboxID   string              `json:"sandboxId"`
	SandboxName string              `json:"sandboxName"`
	EntryPoints []SandboxEntryPoint `json:"entryPoints"`
}

type ErrorResponse struct {
	Message string `json:"message"`
}

package workloadmanager

import (
	"net/http"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/agentcube/agentcube/pkg/common/types"
)

type ErrorResponse struct {
	Message string `json:"message"`
}

func (s *Server) handleAgentRuntimeCreate(c *gin.Context) {
	var req types.CreateSandboxRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, ErrorResponse{Message: err.Error()})
		return
	}

	if err := req.Validate(); err != nil {
		c.JSON(http.StatusBadRequest, ErrorResponse{Message: err.Error()})
		return
	}

	sessionID := generateSessionID()
	sandboxInfo := &types.SandboxInfo{
		Kind:             types.AgentRuntimeKind,
		SandboxID:        sessionID,
		SandboxNamespace: req.Namespace,
		Name:             req.Name,
		SessionID:        sessionID,
		CreatedAt:        time.Now(),
		ExpiresAt:        time.Now().Add(DefaultSandboxTTL),
		Status:           "Creating",
	}

	c.JSON(http.StatusOK, types.CreateSandboxResponse{
		SessionID:   sessionID,
		SandboxID:   sandboxInfo.SandboxID,
		SandboxName: sandboxInfo.Name,
		EntryPoints: sandboxInfo.EntryPoints,
	})
}

func (s *Server) handleCodeInterpreterCreate(c *gin.Context) {
	var req types.CreateSandboxRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, ErrorResponse{Message: err.Error()})
		return
	}

	if err := req.Validate(); err != nil {
		c.JSON(http.StatusBadRequest, ErrorResponse{Message: err.Error()})
		return
	}

	sessionID := generateSessionID()
	sandboxInfo := &types.SandboxInfo{
		Kind:             types.CodeInterpreterKind,
		SandboxID:        sessionID,
		SandboxNamespace: req.Namespace,
		Name:             req.Name,
		SessionID:        sessionID,
		CreatedAt:        time.Now(),
		ExpiresAt:        time.Now().Add(DefaultSandboxTTL),
		Status:           "Creating",
	}

	c.JSON(http.StatusOK, types.CreateSandboxResponse{
		SessionID:   sessionID,
		SandboxID:   sandboxInfo.SandboxID,
		SandboxName: sandboxInfo.Name,
		EntryPoints: sandboxInfo.EntryPoints,
	})
}

func (s *Server) handleDeleteSandbox(c *gin.Context) {
	sessionID := c.Param("sessionId")

	c.JSON(http.StatusOK, gin.H{"status": "deleted", "sessionId": sessionID})
}

func generateSessionID() string {
	return time.Now().Format("20060102150405") + "-" + randomString(8)
}

func randomString(n int) string {
	const letters = "abcdefghijklmnopqrstuvwxyz0123456789"
	b := make([]byte, n)
	for i := range b {
		b[i] = letters[time.Now().UnixNano()%int64(len(letters))]
	}
	return string(b)
}

package workloadmanager

import (
	"context"
	"fmt"
	"log"
	"net/http"
	"os"
	"os/signal"
	"syscall"
	"time"

	"github.com/gin-gonic/gin"
	"golang.org/x/net/http2"
	"golang.org/x/net/http2/h2c"
)

type Server struct {
	config          *Config
	router          *gin.Engine
	httpServer      *http.Server
	k8sClient       *K8sClient
	sandboxController *SandboxReconciler
	tokenCache      *TokenCache
	informers       *Informers
	storeClient     interface{}
	wg              chan struct{}
}

func NewServer(config *Config) *Server {
	gin.SetMode(gin.ReleaseMode)
	router := gin.New()

	s := &Server{
		config:     config,
		router:     router,
		tokenCache: NewTokenCache(1000, 5*time.Minute),
		wg:         make(chan struct{}),
	}

	s.setupRoutes()
	return s
}

func (s *Server) setupRoutes() {
	s.router.Use(loggingMiddleware())
	s.router.Use(authMiddleware(s))

	s.router.GET("/health", s.handleHealth)

	v1 := s.router.Group("/v1")
	{
		v1.POST("/agent-runtime", s.handleAgentRuntimeCreate)
		v1.POST("/code-interpreter", s.handleCodeInterpreterCreate)
		v1.DELETE("/agent-runtime/sessions/:sessionId", s.handleDeleteSandbox)
		v1.DELETE("/code-interpreter/sessions/:sessionId", s.handleDeleteSandbox)
	}
}

func (s *Server) Start() error {
	addr := fmt.Sprintf(":%d", s.config.Port)

	h2s := &http2.Server{}
	handler := h2c.NewHandler(s.router, h2s)

	s.httpServer = &http.Server{
		Addr:              addr,
		Handler:           handler,
		ReadHeaderTimeout: 10 * time.Second,
	}

	log.Printf("Starting Workload Manager on %s", addr)

	if s.config.EnableTLS {
		return s.httpServer.ListenAndServeTLS(s.config.TLSCert, s.config.TLSKey)
	}

	return s.httpServer.ListenAndServe()
}

func (s *Server) Stop() error {
	close(s.wg)

	ctx, cancel := context.WithTimeout(context.Background(), 15*time.Second)
	defer cancel()

	if s.httpServer != nil {
		return s.httpServer.Shutdown(ctx)
	}
	return nil
}

func (s *Server) handleHealth(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "healthy"})
}

func RunServer(config *Config) error {
	server := NewServer(config)

	sigChan := make(chan os.Signal, 1)
	signal.Notify(sigChan, syscall.SIGINT, syscall.SIGTERM)

	go func() {
		if err := server.Start(); err != nil && err != http.ErrServerClosed {
			log.Fatalf("Failed to start server: %v", err)
		}
	}()

	<-sigChan
	return server.Stop()
}

