	"time"

	authv1 "k8s.io/api/authentication/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/client-go/kubernetes"
)

type TokenCache struct {
	cache map[string]*cacheEntry
	mu    sync.RWMutex
	size  int
	ttl   time.Duration
}

type cacheEntry struct {
	username  string
	namespace string
	expiresAt time.Time
	publicKey *rsa.PublicKey
}

func NewTokenCache(size int, ttl time.Duration) *TokenCache {
	return &TokenCache{
		cache: make(map[string]*cacheEntry),
		size:  size,
		ttl:   ttl,
	}
}

func (tc *TokenCache) Get(token string) (*cacheEntry, bool) {
	tc.mu.RLock()
	defer tc.mu.RUnlock()
	entry, ok := tc.cache[token]
	if !ok {
		return nil, false
	}
	if time.Now().After(entry.expiresAt) {
		return nil, false
	}
	return entry, true
}

func (tc *TokenCache) Set(token string, entry *cacheEntry) {
	tc.mu.Lock()
	defer tc.mu.Unlock()

	if len(tc.cache) >= tc.size {
		for k := range tc.cache {
			delete(tc.cache, k)
			break
		}
	}

	entry.expiresAt = time.Now().Add(tc.ttl)
	tc.cache[token] = entry
}

func (s *Server) AuthMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		if !s.config.EnableAuth {
			c.Next()
			return
		}

		token := c.GetHeader("Authorization")
		if token == "" {
			c.JSON(401, gin.H{"error": "missing authorization"})
			c.Abort()
			return
		}

		if entry, ok := s.tokenCache.Get(token); ok {
			c.Set("username", entry.username)
			c.Set("namespace", entry.namespace)
			c.Next()
			return
		}

		c.Next()
	}
}

func validateServiceAccountToken(clientset kubernetes.Interface, token, namespace string) (*authv1.TokenReview, error) {
	tokenReview := &authv1.TokenReview{
		Spec: authv1.TokenReviewSpec{
			Token: token,
		},
	}

	result, err := clientset.AuthenticationV1().TokenReviews().Create(
		context.Background(),
		tokenReview,
		metav1.CreateOptions{},
	)
	if err != nil {
		return nil, err
	}

	return result, nil
}

