)

type K8sClient struct {
	clientset     kubernetes.Interface
	dynamicClient dynamic.Interface
	scheme        *runtime.Scheme
	baseConfig    *rest.Config
	clientCache   map[string]kubernetes.Interface
	mu            sync.RWMutex
}

func NewK8sClient() (*K8sClient, error) {
	config, err := rest.InClusterConfig()
	if err != nil {
		return nil, err
	}

	config.QPS = 50
	config.Burst = 100

	clientset, err := kubernetes.NewForConfig(config)
	if err != nil {
		return nil, err
	}

	dynamicClient, err := dynamic.NewForConfig(config)
	if err != nil {
		return nil, err
	}

	return &K8sClient{
		clientset:     clientset,
		dynamicClient: dynamicClient,
		baseConfig:    config,
		clientCache:   make(map[string]kubernetes.Interface),
	}, nil
}

func (k *K8sClient) GetOrCreateUserK8sClient(namespace, saName, token string) (kubernetes.Interface, error) {
	cacheKey := fmt.Sprintf("%s:%s", namespace, saName)

	k.mu.RLock()
	client, ok := k.clientCache[cacheKey]
	k.mu.RUnlock()

	if ok {
		return client, nil
	}

	k.mu.Lock()
	defer k.mu.Unlock()

	userConfig := &rest.Config{
		Host:        k.baseConfig.Host,
		BearerToken: token,
		TLSClientConfig: rest.TLSClientConfig{
			Insecure:   false,
			ServerName: k.baseConfig.ServerName,
		},
		QPS:   50,
		Burst: 100,
	}

	client, err := kubernetes.NewForConfig(userConfig)
	if err != nil {
		return nil, err
	}

	k.clientCache[cacheKey] = client
	return client, nil
}

