func (s *Server) createSandbox(ctx context.Context, req *types.CreateSandboxRequest) (*types.SandboxInfo, error) {
	sessionID := generateSessionID()

	sandboxObj, err := buildSandboxObject(req.Name, req.Namespace, sessionID)
	if err != nil {
		return nil, err
	}

	watchCh := s.sandboxController.WatchSandboxOnce(req.Namespace, req.Name)

	_, err = s.k8sClient.dynamicClient.Resource(SandboxGVR).
		Namespace(req.Namespace).
		Create(ctx, sandboxObj, metav1.CreateOptions{})
	if err != nil {
		return nil, fmt.Errorf("failed to create sandbox: %w", err)
	}

	timeoutCtx, cancel := context.WithTimeout(ctx, 2*time.Minute)
	defer cancel()

	select {
	case <-watchCh:
	case <-timeoutCtx.Done():
		return nil, fmt.Errorf("timeout waiting for sandbox to be ready")
	}

	sandboxInfo := &types.SandboxInfo{
		Kind:             req.Kind,
		SandboxID:        sessionID,
		SandboxNamespace: req.Namespace,
		Name:             req.Name,
		SessionID:        sessionID,
		CreatedAt:        time.Now(),
		ExpiresAt:        time.Now().Add(DefaultSandboxTTL),
		Status:           "Running",
	}

	return sandboxInfo, nil
}

