import (
	"context"
	"encoding/json"
	"fmt"
	"os"
	"time"

	"github.com/agentcube/agentcube/pkg/common/types"
	"github.com/go-redis/redis/v9"
)

type redisStore struct {
	cli                 *redis.Client
	sessionPrefix       string
	expiryIndexKey      string
	lastActivityIndexKey string
}

func newRedisStore() Store {
	addr := os.Getenv("REDIS_ADDR")
	password := os.Getenv("REDIS_PASSWORD")
	passwordRequired := os.Getenv("REDIS_PASSWORD_REQUIRED")

	opts := &redis.Options{
		Addr: addr,
	}

	if password != "" || passwordRequired != "false" {
		opts.Password = password
	}

	cli := redis.NewClient(opts)

	return &redisStore{
		cli:                 cli,
		sessionPrefix:       "session:",
		expiryIndexKey:      "session:expiry",
		lastActivityIndexKey: "session:last_activity",
	}
}

func (r *redisStore) Ping(ctx context.Context) error {
	return r.cli.Ping(ctx).Err()
}

func (r *redisStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := r.sessionKey(sessionID)
	data, err := r.cli.Get(ctx, key).Bytes()
	if err == redis.Nil {
		return nil, ErrNotFound
	}
	if err != nil {
		return nil, err
	}

	var info types.SandboxInfo
	if err := json.Unmarshal(data, &info); err != nil {
		return nil, err
	}

	return &info, nil
}

func (r *redisStore) StoreSandbox(ctx context.Context, info *types.SandboxInfo) error {
	data, err := json.Marshal(info)
	if err != nil {
		return err
	}

	key := r.sessionKey(info.SessionID)
	ttl := time.Until(info.ExpiresAt)

	pipe := r.cli.Pipeline()
	pipe.Set(ctx, key, data, ttl)
	pipe.ZAdd(ctx, r.expiryIndexKey, redis.Z{
		Score:  float64(info.ExpiresAt.Unix()),
		Member: info.SessionID,
	})
	pipe.ZAdd(ctx, r.lastActivityIndexKey, redis.Z{
		Score:  float64(time.Now().Unix()),
		Member: info.SessionID,
	})

	_, err = pipe.Exec(ctx)
	return err
}

func (r *redisStore) UpdateSandbox(ctx context.Context, info *types.SandboxInfo) error {
	return r.StoreSandbox(ctx, info)
}

func (r *redisStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := r.sessionKey(sessionID)

	pipe := r.cli.Pipeline()
	pipe.Del(ctx, key)
	pipe.ZRem(ctx, r.expiryIndexKey, sessionID)
	pipe.ZRem(ctx, r.lastActivityIndexKey, sessionID)

	_, err := pipe.Exec(ctx)
	return err
}

func (r *redisStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	result, err := r.cli.ZRangeByScore(ctx, r.expiryIndexKey, &redis.ZRangeBy{
		Min: "0",
		Max: fmt.Sprintf("%d", before.Unix()),
		Offset: 0,
		Count:  limit,
	}).Result()
	if err != nil {
		return nil, err
	}

	return r.loadSandboxes(ctx, result)
}

func (r *redisStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	result, err := r.cli.ZRangeByScore(ctx, r.lastActivityIndexKey, &redis.ZRangeBy{
		Min: "0",
		Max: fmt.Sprintf("%d", before.Unix()),
		Offset: 0,
		Count:  limit,
	}).Result()
	if err != nil {
		return nil, err
	}

	return r.loadSandboxes(ctx, result)
}

func (r *redisStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	_, err := r.cli.ZAdd(ctx, r.lastActivityIndexKey, redis.Z{
		Score:  float64(at.Unix()),
		Member: sessionID,
	}).Result()
	return err
}

func (r *redisStore) Close() error {
	return r.cli.Close()
}

func (r *redisStore) sessionKey(sessionID string) string {
	return r.sessionPrefix + sessionID
}

func (r *redisStore) loadSandboxes(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return []*types.SandboxInfo{}, nil
	}

	keys := make([]string, len(sessionIDs))
	for i, id := range sessionIDs {
		keys[i] = r.sessionKey(id)
	}

	vals, err := r.cli.MGet(ctx, keys...).Result()
	if err != nil {
		return nil, err
	}

	sandboxes := make([]*types.SandboxInfo, 0, len(sessionIDs))
	for _, val := range vals {
		if val == nil {
			continue
		}
		data, ok := val.(string)
		if !ok {
			continue
		}
		var info types.SandboxInfo
		if err := json.Unmarshal([]byte(data), &info); err != nil {
			continue
		}
		sandboxes = append(sandboxes, &info)
	}

	return sandboxes, nil
}

package store

import (
	"context"
	"encoding/json"
	"os"
	"strings"
	"time"

	"github.com/agentcube/agentcube/pkg/common/types"
	"github.com/valkey-io/valkey-go"
)

type valkeyStore struct {
	cli valkey.Client
}

func newValkeyStore() Store {
	addr := os.Getenv("VALKEY_ADDR")
	password := os.Getenv("VALKEY_PASSWORD")
	disableCache := os.Getenv("VALKEY_DISABLE_CACHE") == "true"
	forceSingle := os.Getenv("VALKEY_FORCE_SINGLE") == "true"

	addrs := strings.Split(addr, ",")

	client, err := valkey.NewClient(valkey.ClientOption{
		InitAddress:  addrs,
		Password:     password,
		DisableCache: disableCache,
		ForceSingle:  forceSingle,
	})
	if err != nil {
		panic(err)
	}

	return &valkeyStore{cli: client}
}

func (v *valkeyStore) Ping(ctx context.Context) error {
	return v.cli.B().Ping().Build()
}

func (v *valkeyStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := "session:" + sessionID
	result := v.cli.Do(ctx, v.cli.B().Get().Key(key).Build())
	data, err := result.AsBytes()
	if err != nil {
		if strings.Contains(err.Error(), "nil") {
			return nil, ErrNotFound
		}
		return nil, err
	}

	var info types.SandboxInfo
	if err := json.Unmarshal(data, &info); err != nil {
		return nil, err
	}

	return &info, nil
}

func (v *valkeyStore) StoreSandbox(ctx context.Context, info *types.SandboxInfo) error {
	data, err := json.Marshal(info)
	if err != nil {
		return err
	}

	key := "session:" + info.SessionID
	ttl := time.Until(info.ExpiresAt)

	v.cli.Do(ctx, v.cli.B().Set().Key(key).Value(string(data)).Ex(ttl).Build())
	v.cli.Do(ctx, v.cli.B().Zadd().Key("session:expiry").ScoreMember().ScoreMember(float64(info.ExpiresAt.Unix()), info.SessionID).Build())
	v.cli.Do(ctx, v.cli.B().Zadd().Key("session:last_activity").ScoreMember().ScoreMember(float64(time.Now().Unix()), info.SessionID).Build())

	return nil
}

func (v *valkeyStore) UpdateSandbox(ctx context.Context, info *types.SandboxInfo) error {
	return v.StoreSandbox(ctx, info)
}

func (v *valkeyStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := "session:" + sessionID

	v.cli.Do(ctx, v.cli.B().Del().Key(key).Build())
	v.cli.Do(ctx, v.cli.B().Zrem().Key("session:expiry").Member(sessionID).Build())
	v.cli.Do(ctx, v.cli.B().Zrem().Key("session:last_activity").Member(sessionID).Build())

	return nil
}

func (v *valkeyStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	result := v.cli.Do(ctx, v.cli.B().Zrangebyscore().Key("session:expiry").Min("0").Max(string(rune(before.Unix()))).Limit().Offset(0).Count(limit).Build())
	sessionIDs, err := result.AsStrSlice()
	if err != nil {
		return nil, err
	}

	return v.loadSandboxes(ctx, sessionIDs)
}

func (v *valkeyStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	result := v.cli.Do(ctx, v.cli.B().Zrangebyscore().Key("session:last_activity").Min("0").Max(string(rune(before.Unix()))).Limit().Offset(0).Count(limit).Build())
	sessionIDs, err := result.AsStrSlice()
	if err != nil {
		return nil, err
	}

	return v.loadSandboxes(ctx, sessionIDs)
}

func (v *valkeyStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	v.cli.Do(ctx, v.cli.B().Zadd().Key("session:last_activity").ScoreMember().ScoreMember(float64(at.Unix()), sessionID).Build())
	return nil
}

func (v *valkeyStore) Close() error {
	v.cli.Close()
	return nil
}

func (v *valkeyStore) loadSandboxes(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return []*types.SandboxInfo{}, nil
	}

	keys := make([]string, len(sessionIDs))
	for i, id := range sessionIDs {
		keys[i] = "session:" + id
	}

	result := v.cli.Do(ctx, v.cli.B().Mget().Key(keys...).Build())
	vals, err := result.AsStrSlice()
	if err != nil {
		return nil, err
	}

	sandboxes := make([]*types.SandboxInfo, 0, len(sessionIDs))
	for _, val := range vals {
		if val == "" {
			continue
		}
		var info types.SandboxInfo
		if err := json.Unmarshal([]byte(val), &info); err != nil {
			continue
		}
		sandboxes = append(sandboxes, &info)
	}

	return sandboxes, nil
}

