func initStore() Store {
	storeType := os.Getenv("STORE_TYPE")
	if storeType == "" {
		storeType = "redis"
	}

	switch storeType {
	case "valkey":
		return newValkeyStore()
	default:
		return newRedisStore()
	}
}

