func (s *Server) handleHealthLive(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "alive"})
}

func (s *Server) handleHealthReady(c *gin.Context) {
	if s.sessionManager == nil {
		c.JSON(http.StatusServiceUnavailable, gin.H{"status": "not ready"})
		return
	}
	c.JSON(http.StatusOK, gin.H{"status": "ready"})
}

func (s *Server) handleAgentInvoke(c *gin.Context) {
	namespace := c.Param("namespace")
	name := c.Param("name")
	path := c.Param("path")

	sessionID := c.GetHeader("x-agentcube-session-id")
	if sessionID == "" {
		sessionID = generateSessionID()
	}

	sandboxInfo, err := s.sessionManager.GetSandboxBySession(c.Request.Context(), sessionID, namespace, name, "AgentRuntime")
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	s.proxyToSandbox(c, sandboxInfo, path)
}

func (s *Server) handleCodeInterpreterInvoke(c *gin.Context) {
	namespace := c.Param("namespace")
	name := c.Param("name")
	path := c.Param("path")

	sessionID := c.GetHeader("x-agentcube-session-id")
	if sessionID == "" {
		sessionID = generateSessionID()
	}

	sandboxInfo, err := s.sessionManager.GetSandboxBySession(c.Request.Context(), sessionID, namespace, name, "CodeInterpreter")
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	s.proxyToSandbox(c, sandboxInfo, path)
}

func generateSessionID() string {
	return time.Now().Format("20060102150405") + "-" + randomString(8)
}

func randomString(n int) string {
	const letters = "abcdefghijklmnopqrstuvwxyz0123456789"
	b := make([]byte, n)
	for i := range b {
		b[i] = letters[time.Now().UnixNano()%int64(len(letters))]
	}
	return string(b)
}

