import (
	"net/http"
	"net/http/httputil"
	"net/url"
	"strings"

	"github.com/agentcube/agentcube/pkg/common/types"
	"github.com/gin-gonic/gin"
)

func (s *Server) proxyToSandbox(c *gin.Context, sandboxInfo *types.SandboxInfo, path string) {
	if len(sandboxInfo.EntryPoints) == 0 {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "no entry points"})
		return
	}

	entryPoint := sandboxInfo.EntryPoints[0]
	for _, ep := range sandboxInfo.EntryPoints {
		if strings.HasPrefix(path, ep.Path) {
			entryPoint = ep
			break
		}
	}

	targetURL, err := url.Parse(entryPoint.Endpoint)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	proxy := httputil.NewSingleHostReverseProxy(targetURL)

	originalDirector := proxy.Director
	proxy.Director = func(req *http.Request) {
		originalDirector(req)
		req.URL.Path = path
		req.URL.RawPath = c.Request.URL.RawPath
		req.URL.RawQuery = c.Request.URL.RawQuery

		req.Host = targetURL.Host

		if sandboxInfo.Kind == types.SandboxKind || sandboxInfo.Kind == types.SandboxClaimsKind {
			token, err := s.jwtManager.GenerateToken(map[string]interface{}{
				"session_id": sandboxInfo.SessionID,
				"sandbox_id": sandboxInfo.SandboxID,
			})
			if err == nil {
				req.Header.Set("Authorization", "Bearer "+token)
			}
		}

		req.Header.Set("x-agentcube-session-id", sandboxInfo.SessionID)
	}

	proxy.ModifyResponse = func(resp *http.Response) error {
		resp.Header.Set("x-agentcube-session-id", sandboxInfo.SessionID)
		return nil
	}

	proxy.ErrorHandler = func(w http.ResponseWriter, r *http.Request, err error) {
		if strings.Contains(err.Error(), "connection refused") {
			c.JSON(http.StatusBadGateway, gin.H{"error": "upstream connection refused"})
			return
		}
		if strings.Contains(err.Error(), "timeout") {
			c.JSON(http.StatusGatewayTimeout, gin.H{"error": "upstream timeout"})
			return
		}
		c.JSON(http.StatusBadGateway, gin.H{"error": err.Error()})
	}

	proxy.ServeHTTP(c.Writer, c.Request)
}

package router

import (
	"context"
	"crypto/rand"
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"os"
	"time"

	"github.com/golang-jwt/jwt/v5"
	corev1 "k8s.io/api/core/v1"
	k8serrors "k8s.io/apimachinery/pkg/api/errors"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/client-go/kubernetes"
)

const (
	IdentitySecretName   = "picod-router-identity"
	PrivateKeyDataKey    = "private.pem"
	PublicKeyDataKey     = "public.pem"
)

type JWTManager struct {
	privateKey *rsa.PrivateKey
	publicKey  *rsa.PublicKey
	clientset  kubernetes.Interface
}

func NewJWTManager() *JWTManager {
	privateKey, _ := rsa.GenerateKey(rand.Reader, 2048)

	jm := &JWTManager{
		privateKey: privateKey,
		publicKey:  &privateKey.PublicKey,
	}

	return jm
}

func (jm *JWTManager) GenerateToken(claims map[string]interface{}) (string, error) {
	tokenClaims := jwt.MapClaims{
		"exp": time.Now().Add(5 * time.Minute).Unix(),
		"iat": time.Now().Unix(),
		"iss": "agentcube-router",
	}

	for k, v := range claims {
		tokenClaims[k] = v
	}

	token := jwt.NewWithClaims(jwt.SigningMethodRS256, tokenClaims)
	return token.SignedString(jm.privateKey)
}

func (jm *JWTManager) TryStoreOrLoadJWTKeySecret(ctx context.Context, clientset kubernetes.Interface, namespace string) error {
	secret := &corev1.Secret{
		ObjectMeta: metav1.ObjectMeta{
			Name:      IdentitySecretName,
			Namespace: namespace,
		},
		Data: map[string][]byte{
			PrivateKeyDataKey: pem.EncodeToMemory(&pem.Block{
				Type:  "RSA PRIVATE KEY",
				Bytes: x509.MarshalPKCS1PrivateKey(jm.privateKey),
			}),
			PublicKeyDataKey: pem.EncodeToMemory(&pem.Block{
				Type:  "PUBLIC KEY",
				Bytes: x509.MarshalPKIXPublicKey(jm.publicKey),
			}),
		},
	}

	_, err := clientset.CoreV1().Secrets(namespace).Create(ctx, secret, metav1.CreateOptions{})
	if err != nil {
		if k8serrors.IsAlreadyExists(err) {
			return jm.loadExistingKey(ctx, clientset, namespace)
		}
		return err
	}

	return nil
}

func (jm *JWTManager) loadExistingKey(ctx context.Context, clientset kubernetes.Interface, namespace string) error {
	secret, err := clientset.CoreV1().Secrets(namespace).Get(ctx, IdentitySecretName, metav1.GetOptions{})
	if err != nil {
		return err
	}

	privateBlock, _ := pem.Decode(secret.Data[PrivateKeyDataKey])
	if privateBlock == nil {
		return nil
	}

	privateKey, err := x509.ParsePKCS1PrivateKey(privateBlock.Bytes)
	if err != nil {
		return err
	}

	publicBlock, _ := pem.Decode(secret.Data[PublicKeyDataKey])
	if publicBlock == nil {
		return nil
	}

	publicKey, err := x509.ParsePKIXPublicKey(publicBlock.Bytes)
	if err != nil {
		return err
	}

	jm.privateKey = privateKey
	jm.publicKey = publicKey.(*rsa.PublicKey)

	return nil
}

package router

import (
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"os"
	"time"

	"github.com/agentcube/agentcube/pkg/common/types"
	"github.com/agentcube/agentcube/pkg/store"
)

type SessionManager interface {
	GetSandboxBySession(ctx context.Context, sessionID, namespace, name, kind string) (*types.SandboxInfo, error)
}

type manager struct {
	storeClient      store.Store
	workloadMgrAddr  string
	httpClient       *http.Client
	authToken        string
}

func NewSessionManager(storeClient store.Store) SessionManager {
	workloadMgrAddr := os.Getenv("WORKLOAD_MANAGER_URL")
	if workloadMgrAddr == "" {
		workloadMgrAddr = "http://localhost:8080"
	}

	transport := &http.Transport{
		MaxIdleConns:        100,
		MaxIdleConnsPerHost: 10,
		IdleConnTimeout:     90 * time.Second,
		ForceAttemptHTTP2:   true,
	}

	httpClient := &http.Client{
		Transport: transport,
		Timeout:   2 * time.Minute,
	}

	authToken, _ := os.ReadFile("/var/run/secrets/kubernetes.io/serviceaccount/token")

	return &manager{
		storeClient:     storeClient,
		workloadMgrAddr: workloadMgrAddr,
		httpClient:      httpClient,
		authToken:       string(authToken),
	}
}

func (m *manager) GetSandboxBySession(ctx context.Context, sessionID, namespace, name, kind string) (*types.SandboxInfo, error) {
	sandbox, err := m.storeClient.GetSandboxBySessionID(ctx, sessionID)
	if err == nil {
		return sandbox, nil
	}
	if err != store.ErrNotFound {
		return nil, err
	}

	url := fmt.Sprintf("%s/v1/%s", m.workloadMgrAddr, kind)
	reqBody := map[string]string{
		"kind":      kind,
		"name":      name,
		"namespace": namespace,
	}

	body, _ := json.Marshal(reqBody)
	req, _ := http.NewRequestWithContext(ctx, "POST", url, body)
	req.Header.Set("Content-Type", "application/json")
	req.Header.Set("Authorization", "Bearer "+m.authToken)

	resp, err := m.httpClient.Do(req)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()

	var result types.CreateSandboxResponse
	if err := json.NewDecoder(resp.Body).Decode(&result); err != nil {
		return nil, err
	}

	sandbox = &types.SandboxInfo{
		Kind:             kind,
		SandboxID:        result.SandboxID,
		SandboxNamespace: namespace,
		Name:             result.SandboxName,
		EntryPoints:      result.EntryPoints,
		SessionID:        result.SessionID,
		CreatedAt:        time.Now(),
		ExpiresAt:        time.Now().Add(8 * time.Hour),
		Status:           "Running",
	}

	return sandbox, nil
}

