import (
	"context"
	"encoding/json"
	"io"
	"net/http"
	"strings"
	"time"
)

func (jm *JWTManager) TryStoreOrLoadJWTKeySecret(ctx context.Context, clientset kubernetes.Interface, namespace string) error {
	secret := &corev1.Secret{
		ObjectMeta: metav1.ObjectMeta{
			Name:      IdentitySecretName,
			Namespace: namespace,
		},
		Data: map[string][]byte{
			PrivateKeyDataKey: pem.EncodeToMemory(&pem.Block{
				Type:  "RSA PRIVATE KEY",
				Bytes: x509.MarshalPKCS1PrivateKey(jm.privateKey),
			}),
			PublicKeyDataKey: x509.MarshalPKIXPublicKey(jm.publicKey),
		},
	}

	_, err := clientset.CoreV1().Secrets(namespace).Create(ctx, secret, metav1.CreateOptions{})
	if err != nil {
		if k8serrors.IsAlreadyExists(err) {
			return jm.loadExistingKey(ctx, clientset, namespace)
		}
		return err
	}

	return nil
}

func loadExistingKey(ctx context.Context, clientset kubernetes.Interface, namespace string) error {
	secret, err := clientset.CoreV1().Secrets(namespace).Get(ctx, IdentitySecretName, metav1.GetOptions{})
	if err != nil {
		return err
	}

	privateBlock, _ := pem.Decode(secret.Data[PrivateKeyDataKey])
	if privateBlock == nil {
		return nil
	}

	privateKey, err := x509.ParsePKCS1PrivateKey(privateBlock.Bytes)
	if err != nil {
		return err
	}

	publicBlock, _ := pem.Decode(secret.Data[PublicKeyDataKey])
	if publicBlock == nil {
		return nil
	}

	publicKey, err := x509.ParsePKIXPublicKey(publicBlock.Bytes)
	if err != nil {
		return err
	}

	return nil
}

