package picod

import (
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"io"
	"net/http"
	"os"
	"strings"
	"sync"
	"time"

	"github.com/golang-jwt/jwt/v5"
	"github.com/gin-gonic/gin"
)

type AuthManager struct {
	publicKey *rsa.PublicKey
	mu        sync.RWMutex
}

func NewAuthManager() *AuthManager {
	return &AuthManager{}
}

func (am *AuthManager) LoadPublicKeyFromEnv() error {
	keyData := os.Getenv(PublicKeyEnvVar)
	if keyData == "" {
		return nil
	}

	block, _ := pem.Decode([]byte(keyData))
	if block == nil {
		return nil
	}

	pub, err := x509.ParsePKIXPublicKey(block.Bytes)
	if err != nil {
		return err
	}

	rsaPub, ok := pub.(*rsa.PublicKey)
	if !ok {
		return nil
	}

	am.mu.Lock()
	am.publicKey = rsaPub
	am.mu.Unlock()

	return nil
}

func (am *AuthManager) AuthMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		am.mu.RLock()
		publicKey := am.publicKey
		am.mu.RUnlock()

		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.JSON(401, gin.H{"error": "missing authorization"})
			c.Abort()
			return
		}

		tokenString := strings.TrimPrefix(authHeader, "Bearer ")

		token, err := jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
			if _, ok := token.Method.(*jwt.SigningMethodRSA); !ok {
				return nil, nil
			}
			return publicKey, nil
		}, jwt.WithExpirationRequired(), jwt.WithIssuedAt(), jwt.WithLeeway(1*time.Minute))

		if err != nil || !token.Valid {
			c.JSON(401, gin.H{"error": "invalid token"})
			c.Abort()
			return
		}

		c.Request.Body = http.MaxBytesReader(c.Writer, c.Request.Body, MaxBodySize)
		c.Next()
	}
}

package picod

import (
	"fmt"
	"path/filepath"
)

func sanitizePath(p string) (string, error) {
	workspace := "/workspace"
	cleanPath := filepath.Clean(p)

	resolvedWorkspace, err := filepath.EvalSymlinks(workspace)
	if err != nil {
		return "", err
	}

	targetPath := filepath.Join(resolvedWorkspace, cleanPath)

	resolvedPath, err := filepath.EvalSymlinks(targetPath)
	if err != nil {
		if !os.IsNotExist(err) {
			return "", err
		}
		return targetPath, nil
	}

	if !filepath.HasPrefix(resolvedPath, resolvedWorkspace) {
		return "", fmt.Errorf("path escapes workspace")
	}

	return resolvedPath, nil
}

