import (
	"flag"
	"os"

	"k8s.io/apimachinery/pkg/runtime"
	clientgoscheme "k8s.io/client-go/kubernetes/scheme"
	"sigs.k8s.io/controller-runtime/pkg/client/config"
	"sigs.k8s.io/controller-runtime/pkg/manager"
	"sigs.k8s.io/controller-runtime/pkg/manager/signals"
)

func main() {
	scheme := runtime.NewScheme()
	_ = clientgoscheme.AddToScheme(scheme)

	mgr, err := manager.New(config.GetConfigOrDie(), manager.Options{
		MetricsBindAddress:     "0",
		HealthProbeBindAddress: "0",
		Scheme:                 scheme,
	})
	if err != nil {
		os.Exit(1)
	}

	if err := (&Reconciler{
		Client: mgr.GetClient(),
		Scheme: mgr.GetScheme(),
	}).SetupWithManager(mgr); err != nil {
		os.Exit(1)
	}

	if err := mgr.Start(signals.SetupSignalHandler()); err != nil {
		os.Exit(1)
	}
}

package agentd

import (
	"context"
	"time"

	corev1 "k8s.io/api/core/v1"
	k8serrors "k8s.io/apimachinery/pkg/api/errors"
	"k8s.io/apimachinery/pkg/types"
	"sigs.k8s.io/controller-runtime/pkg/client"
	"sigs.k8s.io/controller-runtime/pkg/manager"
	"sigs.k8s.io/controller-runtime/pkg/reconcile"
)

const (
	SessionExpirationTimeout = 15 * time.Minute
	LastActivityAnnotationKey = "agentcube.volcano.sh/last-activity"
)

type Reconciler struct {
	Client client.Client
	Scheme *runtime.Scheme
}

func (r *Reconciler) Reconcile(ctx context.Context, req reconcile.Request) (reconcile.Result, error) {
	sandbox := &corev1.Pod{}
	if err := r.Client.Get(ctx, req.NamespacedName, sandbox); err != nil {
		if k8serrors.IsNotFound(err) {
			return reconcile.Result{}, nil
		}
		return reconcile.Result{}, err
	}

	lastActivityStr := sandbox.Annotations[LastActivityAnnotationKey]
	if lastActivityStr == "" {
		return reconcile.Result{}, nil
	}

	lastActivity, err := time.Parse(time.RFC3339, lastActivityStr)
	if err != nil {
		return reconcile.Result{}, nil
	}

	expiration := lastActivity.Add(SessionExpirationTimeout)

	if time.Now().After(expiration) {
		if err := r.Client.Delete(ctx, sandbox); err != nil {
			if !k8serrors.IsNotFound(err) {
				return reconcile.Result{}, err
			}
		}
		return reconcile.Result{}, nil
	}

	requeueAfter := time.Until(expiration)
	if requeueAfter < 0 {
		requeueAfter = time.Second
	}

	return reconcile.Result{RequeueAfter: requeueAfter}, nil
}

func (r *Reconciler) SetupWithManager(mgr manager.Manager) error {
	return nil
}

